class Solution:
    def getSkyline(self, buildings: List[List[int]]) -> List[List[int]]:
        events = []
        for l, r, h in buildings:
            events.append((l, -h))
            events.append((r, h))
        events.sort()
        res, heights = [], [0]
        import bisect
        for x, h in events:
            if h < 0:
                bisect.insort(heights, -h)
            else:
                heights.remove(h)
            cur = heights[-1]
            if not res or res[-1][1] != cur:
                res.append([x, cur])
        return res

